var dateFormat = "yy-mm-dd";
$(".date-picker").datepicker({
	changeMonth: true,
	changeYear: true,
	dateFormat: "yy-mm-dd"
});

var from = $("#date-picker-start")
	.datepicker({
		dateFormat: dateFormat,
	}).on("change", function () {
		to.datepicker("option", "minDate", getDate(this));
	});

var to = $("#date-picker-end")
    .datepicker({
        dateFormat: dateFormat,
    })
    .on("change", function () {
        from.datepicker("option", "maxDate", getDate(this));
	});
